package javagen

import (
	"bytes"
	"fmt"
	"go/format"
	"os"
	"path/filepath"
	"strings"
	"text/template"
)

// generatedHeader is prepended to all generated files. Split to avoid
// the clean target matching this source file.
var generatedHeader = "// Code generated by javagen. DO NOT " + "EDIT.\n\n"

// templateOrder defines which templates are rendered and in what order.
// "class.go.tmpl" and "type.go.tmpl" are handled separately (per class/data class).
// "constants.go.tmpl" is rendered into a consts/ sub-package (see renderConstsSubpackage).
var templateOrder = []string{
	"package.go.tmpl",
	"init.go.tmpl",
	"callbacks.go.tmpl",
}

// Generate is the main entry point. It loads spec + overlay, merges them,
// renders templates, and writes output files.
//
// The goModule parameter is the Go module path (e.g. "github.com/xaionaro-go/jni").
// Output directories and Go package names are derived from the spec's go_import
// field by stripping the module prefix.
func Generate(specPath, overlayPath, templatesDir, outputDir, goModule string) error {
	spec, err := LoadSpec(specPath)
	if err != nil {
		return fmt.Errorf("load spec: %w", err)
	}

	overlay, err := LoadOverlay(overlayPath)
	if err != nil {
		return fmt.Errorf("load overlay: %w", err)
	}

	merged, err := Merge(spec, overlay)
	if err != nil {
		return fmt.Errorf("merge: %w", err)
	}

	// Derive output directory from go_import by stripping the module prefix.
	// e.g. "github.com/xaionaro-go/jni/hardware/camera" → "hardware/camera"
	relDir := strings.TrimPrefix(spec.GoImport, goModule+"/")

	// Derive Go package name from the last segment of go_import.
	// e.g. "github.com/xaionaro-go/jni/net/wifi/p2p" → "p2p"
	goPackageName := filepath.Base(spec.GoImport)
	merged.Package = goPackageName

	templates, err := loadTemplates(templatesDir)
	if err != nil {
		return fmt.Errorf("load templates: %w", err)
	}

	pkgDir := filepath.Join(outputDir, relDir)
	if err := os.MkdirAll(pkgDir, 0o755); err != nil {
		return fmt.Errorf("mkdir: %w", err)
	}

	cleanStaleFiles(pkgDir)

	for _, tmplName := range templateOrder {
		if !shouldRender(tmplName, merged) {
			continue
		}
		if templates.Lookup(tmplName) == nil {
			continue
		}
		outputFile := templateOutputFile(tmplName)
		if err := renderTemplate(templates, tmplName, merged, filepath.Join(pkgDir, outputFile)); err != nil {
			return fmt.Errorf("render %s: %w", tmplName, err)
		}
	}

	// Render each class to its own <type_name>.go file.
	// Skip classes that would produce empty files (e.g. static_only with no methods).
	if templates.Lookup("class.go.tmpl") != nil {
		for _, cls := range merged.Classes {
			if !classNeedsFile(&cls) {
				continue
			}
			data := &classRenderData{
				Package:     merged.Package,
				MergedClass: cls,
			}
			outputFile := goTypeToFileName(cls.GoType)
			if err := renderTemplate(templates, "class.go.tmpl", data, filepath.Join(pkgDir, outputFile)); err != nil {
				return fmt.Errorf("render class %s: %w", cls.GoType, err)
			}
		}
	}

	// Render each data class to its own <type_name>.go file.
	if templates.Lookup("type.go.tmpl") != nil {
		for _, dc := range merged.DataClasses {
			data := &dataClassRenderData{
				Package:         merged.Package,
				MergedDataClass: dc,
			}
			outputFile := goTypeToFileName(dc.GoType)
			if err := renderTemplate(templates, "type.go.tmpl", data, filepath.Join(pkgDir, outputFile)); err != nil {
				return fmt.Errorf("render type %s: %w", dc.GoType, err)
			}
		}
	}

	// Render constants into a consts/ sub-package so consumers can import
	// them without pulling in CGO-dependent parent package code.
	if len(merged.ConstantGroups) > 0 {
		if err := renderConstsSubpackage(templates, merged, pkgDir); err != nil {
			return fmt.Errorf("render consts sub-package: %w", err)
		}

		// Also generate alias re-exports in the parent package for convenience.
		constsImport := spec.GoImport + "/consts"
		if err := renderConstAliases(merged, pkgDir, constsImport); err != nil {
			return fmt.Errorf("render const aliases: %w", err)
		}
	}

	return nil
}

// classRenderData is the template context for rendering a single class.
type classRenderData struct {
	Package string
	MergedClass
}

// dataClassRenderData is the template context for rendering a single data class.
type dataClassRenderData struct {
	Package string
	MergedDataClass
}

func loadTemplates(dir string) (*template.Template, error) {
	funcMap := template.FuncMap{
		"lower":                 strings.ToLower,
		"upper":                 strings.ToUpper,
		"title":                 strings.Title, //nolint:staticcheck
		"join":                  strings.Join,
		"isManager":             IsManager,
		"managerData":           ManagerConstructorData,
		"buildCallbackType":     BuildCallbackType,
		"buildCallbackDispatch": BuildCallbackDispatch,
		"javaClassToSlash":      JavaClassToSlash,
		"jniTypeSignature":      JNITypeSignature,
		"resolveType":           ResolveType,
		"paramConversionCode":   ParamConversionCode,
		"returnConversionCode":  ReturnConversionCode,
	}

	pattern := filepath.Join(dir, "*.go.tmpl")
	matches, err := filepath.Glob(pattern)
	if err != nil {
		return nil, fmt.Errorf("glob templates: %w", err)
	}
	if len(matches) == 0 {
		// No templates found; return an empty template set.
		return template.New("").Funcs(funcMap), nil
	}

	return template.New("").Funcs(funcMap).ParseGlob(pattern)
}

func renderTemplate(tmpl *template.Template, name string, data any, outputPath string) error {
	// Preserve hand-maintained files: if the target already exists and
	// was NOT generated by javagen, do not overwrite it.
	if isHandMaintainedFile(outputPath) {
		return nil
	}

	var buf bytes.Buffer
	if err := tmpl.ExecuteTemplate(&buf, name, data); err != nil {
		return fmt.Errorf("execute template %s: %w", name, err)
	}

	// Prepend the generated header.
	src := generatedHeader + buf.String()

	// Run gofmt.
	formatted, err := format.Source([]byte(src))
	if err != nil {
		// Write unformatted so the user can debug.
		if writeErr := os.WriteFile(outputPath, []byte(src), 0o644); writeErr != nil {
			return fmt.Errorf("write unformatted: %w (format error: %w)", writeErr, err)
		}
		return fmt.Errorf("gofmt %s: %w", name, err)
	}

	return os.WriteFile(outputPath, formatted, 0o644)
}

// isHandMaintainedFile reports whether the file at path exists and is
// NOT generated by javagen (i.e. it is hand-maintained and should not
// be overwritten by the code generator).
func isHandMaintainedFile(path string) bool {
	data, err := os.ReadFile(path)
	if err != nil {
		return false
	}
	return !strings.Contains(string(data), "Code generated by javagen. DO NOT EDIT.")
}

func cleanStaleFiles(dir string) {
	entries, err := os.ReadDir(dir)
	if err != nil {
		return
	}
	for _, e := range entries {
		if e.IsDir() || !strings.HasSuffix(e.Name(), ".go") {
			continue
		}
		path := filepath.Join(dir, e.Name())
		data, err := os.ReadFile(path)
		if err != nil {
			continue
		}
		if strings.Contains(string(data), "Code generated by javagen. DO NOT EDIT.") {
			_ = os.Remove(path)
		}
	}
}

// GoImportToRelDir strips the Go module prefix from a go_import path
// to produce the relative output directory.
// e.g. GoImportToRelDir("github.com/foo/bar/hw/cam", "github.com/foo/bar") → "hw/cam"
func GoImportToRelDir(goImport, goModule string) string {
	return strings.TrimPrefix(goImport, goModule+"/")
}

// renderConstsSubpackage renders constants into {pkgDir}/consts/consts.go
// with "package consts". The sub-package is CGO-free (no imports).
func renderConstsSubpackage(templates *template.Template, merged *MergedSpec, pkgDir string) error {
	tmpl := templates.Lookup("constants.go.tmpl")
	if tmpl == nil {
		return nil
	}

	constsDir := filepath.Join(pkgDir, "consts")
	if err := os.MkdirAll(constsDir, 0o755); err != nil {
		return fmt.Errorf("mkdir consts: %w", err)
	}

	cleanStaleFiles(constsDir)

	// Render with "package consts" instead of the parent package name.
	constsData := &MergedSpec{
		Package:        "consts",
		ConstantGroups: merged.ConstantGroups,
	}

	return renderTemplate(tmpl, "constants.go.tmpl", constsData, filepath.Join(constsDir, "consts.go"))
}

// renderConstAliases generates {pkgDir}/constants.go with alias re-exports
// of every constant from the consts sub-package. This lets users of the
// CGO-dependent parent package access constants directly (e.g. location.GpsProvider)
// without importing the consts sub-package.
func renderConstAliases(merged *MergedSpec, pkgDir, constsImport string) error {
	outputPath := filepath.Join(pkgDir, "constants.go")

	// Preserve hand-maintained files.
	if isHandMaintainedFile(outputPath) {
		return nil
	}

	var buf bytes.Buffer
	fmt.Fprintf(&buf, "package %s\n\n", merged.Package)
	fmt.Fprintf(&buf, "import %q\n\n", constsImport)

	for _, grp := range merged.ConstantGroups {
		if grp.GoType != "" {
			fmt.Fprintf(&buf, "// %s is a typed constant defined in the consts sub-package.\n", grp.GoType)
			fmt.Fprintf(&buf, "type %s = consts.%s\n\n", grp.GoType, grp.GoType)
		}

		buf.WriteString("const (\n")
		for _, c := range grp.Values {
			fmt.Fprintf(&buf, "\t%s = consts.%s\n", c.GoName, c.GoName)
		}
		buf.WriteString(")\n\n")
	}

	src := generatedHeader + buf.String()

	formatted, err := format.Source([]byte(src))
	if err != nil {
		if writeErr := os.WriteFile(outputPath, []byte(src), 0o644); writeErr != nil {
			return fmt.Errorf("write unformatted: %w (format error: %w)", writeErr, err)
		}
		return fmt.Errorf("gofmt constants.go: %w", err)
	}

	return os.WriteFile(outputPath, formatted, 0o644)
}

func shouldRender(tmplName string, merged *MergedSpec) bool {
	switch tmplName {
	case "callbacks.go.tmpl":
		return len(merged.Callbacks) > 0
	default:
		return true
	}
}

func templateOutputFile(tmplName string) string {
	// "manager.go.tmpl" → "manager.go"
	// "package.go.tmpl" → "doc.go"
	switch tmplName {
	case "package.go.tmpl":
		return "doc.go"
	default:
		return strings.TrimSuffix(tmplName, ".tmpl")
	}
}

// classNeedsFile returns true if a class should produce its own .go file.
// Classes with no struct and no instance methods (e.g. static_only) are skipped.
func classNeedsFile(cls *MergedClass) bool {
	switch cls.Obtain {
	case "system_service", "constructor", "static_factory", "static_fields":
		return true
	}
	return len(cls.Methods) > 0
}

// goTypeToFileName converts a Go type name to a snake_case .go filename.
// Examples:
//
//	"Location"    → "location.go"
//	"ScanResult"  → "scan_result.go"
//	"GATTClient"  → "gatt_client.go"
//	"TTS"         → "tts.go"
func goTypeToFileName(goType string) string {
	runes := []rune(goType)
	var b strings.Builder
	for i, r := range runes {
		if r >= 'A' && r <= 'Z' {
			if i > 0 {
				prev := runes[i-1]
				prevLower := prev >= 'a' && prev <= 'z'
				// Insert underscore if previous char is lowercase,
				// or if this starts a new word (uppercase followed by lowercase).
				nextLower := i+1 < len(runes) && runes[i+1] >= 'a' && runes[i+1] <= 'z'
				if prevLower || (prev >= 'A' && prev <= 'Z' && nextLower) {
					b.WriteByte('_')
				}
			}
			b.WriteRune(r - 'A' + 'a')
		} else {
			b.WriteRune(r)
		}
	}
	return b.String() + ".go"
}
